sql:
SELECT project_id, SUM(amount) AS total_funding
FROM funding_data
GROUP BY project_id;

SELECT MAX(total_funding) AS highest_total_funding
FROM (
  SELECT project_id, SUM(amount) AS total_funding
  FROM funding_data
  GROUP BY project_id
);

SELECT success_rate
FROM success_rates
WHERE success_rate > 0.5;

SELECT goal_name
FROM funding_goals
WHERE goal_id = 1;

SELECT 
  (AVG(success_rate) * 100) AS average_success_rate
FROM success_rates;

